#!/usr/bin/env bash
# cloud-run-gpu-fleet.sh: GPU-enable the Cloud Run distributed-inference fleet.
#
# Attaches one NVIDIA L4 (no zonal redundancy) to every coordinator / layer
# instance / openai model server while keeping min-instances=0 (scale to zero).
# Cloud Run GPU is GA; with min-instances=0 an idle service costs nothing.
#
# Constraints handled here (learned empirically 2026-06-12):
# - GPU floor is 4 vCPU / 16Gi — services below are bumped to exactly the floor.
# - GPU requires instance-based billing (--no-cpu-throttling).
# - The deploy-time quota check validates the SERVICE-LEVEL max annotation
#   (run.googleapis.com/maxScale, set via --max) AND the revision max
#   (--max-instances) against NvidiaL4GpuAllocNoZonalRedundancyPerProjectRegion.
#   Both must be <= the quota value, so we set both explicitly.
# - Runtime concurrency across the whole project-region is capped by the same
#   quota (currently 3; increase to 60 requested 2026-06-12).
#
# COST WARNING: GPU services bill for the full lifetime of an instance. Any
# Cloud Scheduler warm ping (<15 min interval) keeps a GPU instance up 24/7
# (~$700/mo each). Services with live warm pings are EXCLUDED by default —
# pass --include-warm only after deciding the warm-ping question.
#
# Usage: ./cloud-run-gpu-fleet.sh [--dry-run] [--include-warm] [--only <regex>]

set -uo pipefail

PROJECT="${PROJECT:-neutral-418500}"
REGION="${REGION:-us-central1}"
GPU_TYPE="${GPU_TYPE:-nvidia-l4}"
MAX_INSTANCES="${MAX_INSTANCES:-3}"   # per-service; must be <= L4 no-ZR quota
PARALLEL="${PARALLEL:-4}"

# Services that HAD a live Cloud Scheduler /health warm ping (12-min cadence).
# All warmup jobs were swept and deleted 2026-06-12 (GPU + warm ping = 24/7
# instance-based GPU billing). Run with --include-warm to cover these; the
# exclusion default stays as a guard in case pings ever reappear.
# Source of truth: gcloud scheduler jobs list --location=us-central1 | grep warm
WARM_PINGED="gnosis-openai-deepseek-r1-1-5b gnosis-openai-gemma3-4b-it \
gnosis-openai-llama-3-2-3b gnosis-openai-mistral-7b gnosis-openai-qwen2-5-0-5b \
gnosis-openai-qwen2-5-7b gnosis-openai-qwen3-4b gnosis-openai-qwen3-8b \
gnosis-openai-tinyllama gnosis-openai-whisper inference-flux-4b-coordinator"

DRY_RUN=""
INCLUDE_WARM=""
ONLY=""
while [ $# -gt 0 ]; do
  case "$1" in
    --dry-run) DRY_RUN=true ;;
    --include-warm) INCLUDE_WARM=true ;;
    --only) shift; ONLY="$1" ;;
  esac
  shift
done

is_warm_pinged() {
  local s
  for s in ${WARM_PINGED}; do [ "$s" = "$1" ] && return 0; done
  return 1
}

# ceil cpu to 4 (values like "1000m", "2" -> 4; "4"/"8" kept)
floor_cpu() {
  local cpu="$1"
  case "$cpu" in
    *m) echo 4 ;;
    1|2|3) echo 4 ;;
    *) echo "$cpu" ;;
  esac
}

# ceil memory to 16Gi ("512Mi", "4Gi", "8Gi" -> 16Gi; "16Gi"/"32Gi" kept)
floor_mem() {
  local mem="$1"
  case "$mem" in
    *Mi) echo 16Gi ;;
    1Gi|2Gi|4Gi|8Gi) echo 16Gi ;;
    *) echo "$mem" ;;
  esac
}

enable_gpu() {
  local svc="$1" cpu="$2" mem="$3"
  local want_cpu want_mem
  want_cpu="$(floor_cpu "$cpu")"
  want_mem="$(floor_mem "$mem")"

  if [ -n "$DRY_RUN" ]; then
    echo "[dry-run] $svc: gpu=1 ($GPU_TYPE, no-ZR) cpu=$cpu->$want_cpu mem=$mem->$want_mem max=$MAX_INSTANCES min=0"
    return 0
  fi

  if gcloud run services update "$svc" \
    --project="$PROJECT" --region="$REGION" \
    --gpu=1 --gpu-type="$GPU_TYPE" --no-gpu-zonal-redundancy \
    --no-cpu-throttling \
    --cpu="$want_cpu" --memory="$want_mem" \
    --min-instances=0 --max-instances="$MAX_INSTANCES" --max="$MAX_INSTANCES" \
    --quiet >/dev/null 2>&1; then
    echo "OK   $svc (cpu=$want_cpu mem=$want_mem)"
  else
    echo "FAIL $svc"
    return 1
  fi
}

export -f enable_gpu floor_cpu floor_mem
export PROJECT REGION GPU_TYPE MAX_INSTANCES DRY_RUN

echo "=== Cloud Run GPU fleet rollout ==="
echo "Project: $PROJECT  Region: $REGION  GPU: $GPU_TYPE x1 (no zonal redundancy)"
echo "max-instances: $MAX_INSTANCES  min-instances: 0"
echo ""

TARGETS=$(gcloud run services list --project="$PROJECT" --region="$REGION" \
  --format="csv[no-heading](metadata.name, spec.template.spec.containers[0].resources.limits.cpu, spec.template.spec.containers[0].resources.limits.memory, spec.template.spec.containers[0].resources.limits['nvidia.com/gpu'])" \
  | awk -F, '$1 ~ /^(gnosis-openai-|inference-)/ && $4 == "" {print $1","$2","$3}')

QUEUE=""
SKIPPED=0
while IFS=, read -r svc cpu mem; do
  [ -z "$svc" ] && continue
  if [ -n "$ONLY" ] && ! echo "$svc" | grep -qE "$ONLY"; then continue; fi
  if [ -z "$INCLUDE_WARM" ] && is_warm_pinged "$svc"; then
    echo "SKIP $svc (live warm ping -> 24/7 GPU billing; use --include-warm)"
    SKIPPED=$((SKIPPED + 1))
    continue
  fi
  QUEUE="${QUEUE}${svc},${cpu},${mem}\n"
done <<EOF
$TARGETS
EOF

COUNT=$(printf "%b" "$QUEUE" | grep -c . || true)
echo ""
echo "Updating $COUNT services ($SKIPPED warm-pinged skipped), parallel=$PARALLEL..."
echo ""

printf "%b" "$QUEUE" | xargs -P "$PARALLEL" -I {} bash -c '
  IFS=, read -r svc cpu mem <<< "{}"
  enable_gpu "$svc" "$cpu" "$mem"
'

echo ""
echo "Done. Verify: gcloud run services list --project=$PROJECT --region=$REGION \\"
echo "  --format=\"table(metadata.name, spec.template.spec.containers[0].resources.limits)\" | grep nvidia"
